-- Lalin VM — For-loop opcode handlers

local B = require("experiments.lua_interpreter_vm.src.op._init")
local R, H = B.R, B.H

local op_forloop = R([[
region op_forloop(]] .. H .. [[;
                  next: cont(frame: ptr(Frame), pc: index, base: index, top: index),
                  do_jump: cont(frame: ptr(Frame), pc: index, base: index, top: index),
                  error: cont(code: i32))
entry start()
    let idx_slot: index = base + as(index, a)
    let limit_slot: index = base + as(index, a + 1)
    let step_slot: index = base + as(index, a + 2)
    let idx_val: Value = L.stack[idx_slot]
    let limit_val: Value = L.stack[limit_slot]
    let step_val: Value = L.stack[step_slot]
    if idx_val.tag == @{TAG_INTEGER} and limit_val.tag == @{TAG_INTEGER} and step_val.tag == @{TAG_INTEGER} then
        let idx: i64 = as(i64, idx_val.bits) + as(i64, step_val.bits)
        L.stack[idx_slot] = { tag = @{TAG_INTEGER}, aux = 0, bits = bitcast(u64, idx) }
        let limit: i64 = as(i64, limit_val.bits)
        let step: i64 = as(i64, step_val.bits)
        if (step >= 0 and idx <= limit) or (step < 0 and idx >= limit) then
            L.stack[base + as(index, a + 3)] = L.stack[idx_slot]
            let new_pc: index = as(index, as(i32, pc) + sbx)
            jump do_jump(frame = frame, pc = new_pc, base = base, top = top)
        end
        jump next(frame = frame, pc = pc + 1, base = base, top = top)
    end
    if idx_val.tag == @{TAG_NUM} and limit_val.tag == @{TAG_NUM} and step_val.tag == @{TAG_NUM} then
        let idx: f64 = bitcast(f64, idx_val.bits) + bitcast(f64, step_val.bits)
        L.stack[idx_slot] = { tag = @{TAG_NUM}, aux = 0, bits = bitcast(u64, idx) }
        let limit: f64 = bitcast(f64, limit_val.bits)
        let step: f64 = bitcast(f64, step_val.bits)
        if (step >= 0.0 and idx <= limit) or (step < 0.0 and idx >= limit) then
            L.stack[base + as(index, a + 3)] = L.stack[idx_slot]
            let new_pc: index = as(index, as(i32, pc) + sbx)
            jump do_jump(frame = frame, pc = new_pc, base = base, top = top)
        end
        jump next(frame = frame, pc = pc + 1, base = base, top = top)
    end
    jump error(code = @{ERR_RUNTIME})
end
end
]])

local op_forprep = R([[
region op_forprep(]] .. H .. [[;
                  do_jump: cont(frame: ptr(Frame), pc: index, base: index, top: index),
                  error: cont(code: i32))
entry start()
    let init_slot: index = base + as(index, a)
    let limit_slot: index = base + as(index, a + 1)
    let step_slot: index = base + as(index, a + 2)
    let init_val: Value = L.stack[init_slot]
    let limit_val: Value = L.stack[limit_slot]
    let step_val: Value = L.stack[step_slot]
    if init_val.tag == @{TAG_INTEGER} and limit_val.tag == @{TAG_INTEGER} and step_val.tag == @{TAG_INTEGER} then
        let prepared: i64 = as(i64, init_val.bits) - as(i64, step_val.bits)
        L.stack[init_slot] = { tag = @{TAG_INTEGER}, aux = 0, bits = bitcast(u64, prepared) }
        let new_pc: index = as(index, as(i32, pc) + sbx)
        jump do_jump(frame = frame, pc = new_pc, base = base, top = top)
    end
    if init_val.tag == @{TAG_NUM} and limit_val.tag == @{TAG_NUM} and step_val.tag == @{TAG_NUM} then
        let prepared: f64 = bitcast(f64, init_val.bits) - bitcast(f64, step_val.bits)
        L.stack[init_slot] = { tag = @{TAG_NUM}, aux = 0, bits = bitcast(u64, prepared) }
        let new_pc: index = as(index, as(i32, pc) + sbx)
        jump do_jump(frame = frame, pc = new_pc, base = base, top = top)
    end
    jump error(code = @{ERR_RUNTIME})
end
end
]])

local op_tforprep = R([[
region op_tforprep(]] .. H .. [[;
                   do_jump: cont(frame: ptr(Frame), pc: index, base: index, top: index))
entry start()
    let new_pc: index = as(index, as(i32, pc) + sbx)
    jump do_jump(frame = frame, pc = new_pc, base = base, top = top)
end
end
]])

local op_tforcall = R([[
region op_tforcall(]] .. H .. [[;
                   ]] .. B.MMBIN_CONTS .. [[)
entry start()
    jump error(code = @{ERR_RUNTIME})
end
end
]])

local op_tforloop = R([[
region op_tforloop(]] .. H .. [[;
                   next: cont(frame: ptr(Frame), pc: index, base: index, top: index),
                   do_jump: cont(frame: ptr(Frame), pc: index, base: index, top: index))
entry start()
    let var_val: Value = L.stack[base + as(index, a + 2)]
    if var_val.tag ~= @{TAG_NIL} then
        L.stack[base + as(index, a)] = var_val
        let new_pc: index = as(index, as(i32, pc) - as(i32, bx))
        jump do_jump(frame = frame, pc = new_pc, base = base, top = top)
    end
    jump next(frame = frame, pc = pc + 1, base = base, top = top)
end
end
]])

return {
    op_forloop = op_forloop, op_forprep = op_forprep,
    op_tforprep = op_tforprep, op_tforcall = op_tforcall, op_tforloop = op_tforloop,
}

-- VM ABI contract module/API tests.

package.path = "./lua/?.lua;./lua/?/init.lua;" .. package.path

local ffi = require("ffi")
local lalin = require("lalin")
local vm = require("experiments.lua_interpreter_vm.src.init")
local const = vm.const

assert(vm.contract.vm_abi_version == const.Abi.VM_VERSION, "VM ABI version mismatch")
assert(vm.contract.native_abi_version == const.Abi.NATIVE_VERSION, "native ABI version mismatch")
assert(vm.contract.validator_contract_version == const.Abi.VALIDATOR_VERSION, "validator ABI version mismatch")
assert(vm.contract.sponjit_allowed == false, "SponJIT must remain gated")

ffi.cdef [[
typedef struct { void* next; uint8_t tt; uint8_t marked; } GCHeader;
typedef struct { uint32_t tag; uint32_t aux; uint64_t bits; } Value;
typedef struct {
    GCHeader gc; uint8_t status;
    Value* stack; uint64_t stack_size; uint64_t top;
    void* frames; uint64_t frame_count; uint64_t frame_cap;
    void* open_upvals; void* protected_top;
    void* global; Value err_value;
    uint8_t hookmask; uint8_t allowhook;
    int32_t hookcount; int32_t basehookcount; Value hook;
    uint64_t tbc_head;
    int32_t yieldable; int32_t nonyieldable; int32_t last_error_code; uint32_t flags;
} LuaThread;
]]

local abi = lalin.func {
    vm_abi = vm.api.lua_vm_abi_version_api,
    native_abi = vm.api.lua_native_abi_version_api,
    status_api = vm.api.lua_status_api,
    last_error_api = vm.api.lua_last_error_api,
} [[
abi_check(L: ptr(LuaThread)) -> i32
    let a: i32 = @{vm_abi}()
    let b: i32 = @{native_abi}()
    let s: i32 = @{status_api}(L)
    let e: i32 = @{last_error_api}(L)
    if a ~= 1 then return -1 end
    if b ~= 1 then return -2 end
    if s ~= as(i32, L.status) then return -3 end
    if e ~= L.last_error_code then return -4 end
    return 0
end
]]:compile()

local L = ffi.new("LuaThread[1]")
L[0].status = const.Status.OK
L[0].last_error_code = 123
local r = abi(L)
abi:free()
assert(r == 0, "ABI API check failed: " .. tostring(r))
print("PASS VM ABI contract")
return true

-- Frame/cache and explicit call result-base contract tests.

package.path = "./lua/?.lua;./lua/?/init.lua;" .. package.path

local ffi = require("ffi")
local lalin = require("lalin")
local vm = require("experiments.lua_interpreter_vm.src.init")
local const = vm.const

ffi.cdef [[
typedef struct { void* next; uint8_t tt; uint8_t marked; } GCHeader;
typedef struct { uint32_t tag; uint32_t aux; uint64_t bits; } Value;
typedef struct { uint32_t word; } Instr;
typedef struct {
    GCHeader gc;
    Instr* code; uint64_t code_len;
    Value* constants; uint64_t constants_len;
    void** children; uint64_t children_len;
    int32_t* lineinfo; uint64_t lineinfo_len;
    void* locvars; uint64_t locvars_len;
    void* upvals; uint64_t upvals_len;
    void* source;
    int32_t linedefined; int32_t lastlinedefined;
    uint8_t numparams; uint8_t flag; uint16_t maxstack;
} Proto;
typedef struct { GCHeader gc; void* env; Proto* proto; void** upvals; uint8_t nupvals; } LClosure;
typedef struct {
    Value closure; uint64_t base; uint64_t top; uint64_t pc;
    int32_t wanted; int32_t tailcalls;
    uint16_t resume_mode;
    uint16_t resume_a; uint16_t resume_b; uint16_t resume_c;
    uint64_t resume_pc; uint64_t resume_base; Value resume_value;
    uint64_t result_base; uint64_t call_top;
    uint8_t yieldable; uint8_t flags; uint16_t reserved;
} Frame;
typedef struct {
    GCHeader gc; uint8_t status;
    Value* stack; uint64_t stack_size; uint64_t top;
    Frame* frames; uint64_t frame_count; uint64_t frame_cap;
    void* open_upvals; void* protected_top;
    void* global; Value err_value;
    uint8_t hookmask; uint8_t allowhook;
    int32_t hookcount; int32_t basehookcount; Value hook;
    uint64_t tbc_head;
    int32_t yieldable; int32_t nonyieldable; int32_t last_error_code; uint32_t flags;
} LuaThread;
typedef struct { void* allocator; Value registry; void* mainthread; uint32_t vm_abi_version; uint32_t native_abi_version; } GlobalState;
]]

local function setnil(v) v.tag = const.Tag.NIL; v.aux = 0; v.bits = 0 end
local function setint(v, x) v.tag = const.Tag.INTEGER; v.aux = 0; v.bits = ffi.cast("uint64_t", x) end
local function setclosure(v, cl) v.tag = const.Tag.LCLOSURE; v.aux = 0; v.bits = ffi.cast("uint64_t", cl) end
local function bits_i64(x) return tonumber(ffi.cast("int64_t", x)) end
local function set_ABC(i, op, a, b, c, k)
    i.word = bit.bor(op, bit.lshift(a or 0, 7), bit.lshift(k or 0, 15), bit.lshift(b or 0, 16), bit.lshift(c or 0, 24))
end
local function set_ABx(i, op, a, bx)
    i.word = bit.bor(op, bit.lshift(a or 0, 7), bit.lshift(bx or 0, 15))
end
local function set_AsBx(i, op, a, sbx)
    set_ABx(i, op, a, (sbx or 0) + 65535)
end

local runner = lalin.func { vm_resume = vm.vm_loop.vm_resume } [[
run(L: ptr(LuaThread)) -> i32
    return region -> i32
    entry start()
        emit @{vm_resume}(L, 0;
            ok = ok,
            yielded = yielded,
            runtime_error = err,
            oom = oom)
    end
    block ok(nres: i32) return nres end
    block yielded(nres: i32) return -100 - nres end
    block err(code: i32) return -200 - code end
    block oom() return -999 end
    end
end
]]:compile()

-- Child: return 7
local child_code = ffi.new("Instr[2]")
set_AsBx(child_code[0], const.Op.LOADI, 0, 7)
set_ABC(child_code[1], const.Op.RETURN1, 0, 0, 0, 0)
local child_proto = ffi.new("Proto[1]")
child_proto[0].code = child_code; child_proto[0].code_len = 2; child_proto[0].maxstack = 2
local child_cl = ffi.new("LClosure[1]")
child_cl[0].proto = child_proto

-- Parent: call child into R1, load parent constant into R2, add R1+R2 into R0, return R0.
local parent_code = ffi.new("Instr[6]")
set_ABx(parent_code[0], const.Op.LOADK, 1, 0)
set_ABC(parent_code[1], const.Op.CALL, 1, 1, 2, 0)
set_ABx(parent_code[2], const.Op.LOADK, 2, 1)
set_ABC(parent_code[3], const.Op.ADD, 0, 1, 2, 0)
set_ABC(parent_code[4], const.Op.MMBIN, 0, const.TM.ADD, 0, 0)
set_ABC(parent_code[5], const.Op.RETURN1, 0, 0, 0, 0)
local parent_consts = ffi.new("Value[2]")
setclosure(parent_consts[0], child_cl)
setint(parent_consts[1], 35)
local parent_proto = ffi.new("Proto[1]")
parent_proto[0].code = parent_code; parent_proto[0].code_len = 6
parent_proto[0].constants = parent_consts; parent_proto[0].constants_len = 2; parent_proto[0].maxstack = 4
local parent_cl = ffi.new("LClosure[1]")
parent_cl[0].proto = parent_proto

local stack = ffi.new("Value[64]")
for i = 0, 63 do setnil(stack[i]) end
setclosure(stack[0], parent_cl)
setint(stack[1], 999) -- must not receive child result directly
local frames = ffi.new("Frame[8]")
frames[0].closure = stack[0]
frames[0].base = 1; frames[0].top = 1; frames[0].pc = 0; frames[0].wanted = 1
frames[0].resume_mode = const.Resume.NORMAL; frames[0].result_base = 1; frames[0].call_top = 1; frames[0].yieldable = 1
local global = ffi.new("GlobalState[1]")
local L = ffi.new("LuaThread[1]")
L[0].status = const.Status.OK; L[0].stack = stack; L[0].stack_size = 64; L[0].top = 1
L[0].frames = frames; L[0].frame_count = 1; L[0].frame_cap = 8; L[0].global = global
L[0].yieldable = 1; L[0].nonyieldable = 0; L[0].last_error_code = 0; L[0].flags = 0
global[0].mainthread = L

local nres = runner(L)
runner:free()
if nres ~= 1 then
    print("debug nres", nres, "last_error", L[0].last_error_code, "err_aux", L[0].err_value.aux)
    print("debug stack tags", stack[1].tag, stack[2].tag, stack[3].tag)
    print("debug frame", L[0].frame_count, frames[0].pc, frames[0].base, frames[0].top, "resume", frames[0].resume_pc, frames[0].resume_base, frames[0].resume_a)
    print("debug stack vals", bits_i64(stack[1].bits), bits_i64(stack[2].bits), bits_i64(stack[3].bits))
end
assert(nres == 1, "nested call nres mismatch: " .. tostring(nres))
assert(stack[1].tag == const.Tag.INTEGER and bits_i64(stack[1].bits) == 42, "parent result/cache reload failed")
assert(stack[2].tag == const.Tag.INTEGER and bits_i64(stack[2].bits) == 7, "child result did not land at explicit result_base")
assert(stack[3].tag == const.Tag.INTEGER and bits_i64(stack[3].bits) == 35, "parent constants were not reloaded after child return")
print("PASS VM call/frame contract")
return true

